      seoTitle: "\u0623\u0641\u0636\u0644 \u0627\u0644\u062E\u0635\u0648\u0645\u0627\u062A \u0627\u0644\u0637\u0644\u0627\u0628\u064A\u0629 \u0648\u0645\u0632\u0627\u064A\u0627 \u0628\u0631\u064A\u062F .EDU",
      seoP1: "\u0627\u0644\u062E\u0635\u0648\u0645\u0627\u062A \u0627\u0644\u0637\u0644\u0627\u0628\u064A\u0629 \u064A\u0645\u0643\u0646 \u0623\u0646 \u062A\u0648\u0641\u0631 \u0644\u0643 \u0622\u0644\u0627\u0641 \u0627\u0644\u062F\u0648\u0644\u0627\u0631\u0627\u062A \u0633\u0646\u0648\u064A\u0627\u064B \u0639\u0644\u0649 \u0627\u0644\u0628\u0631\u0645\u062C\u064A\u0627\u062A \u0648\u062E\u062F\u0645\u0627\u062A \u0627\u0644\u0628\u062B \u0627\u0644\u062A\u0631\u0641\u064A\u0647\u064A \u0648\u0645\u0648\u0627\u0631\u062F \u0627\u0644\u062A\u0639\u0644\u0645.",
      discountsTitle: "\u0623\u0641\u0636\u0644 \u0627\u0644\u062E\u0635\u0648\u0645\u0627\u062A \u0627\u0644\u0637\u0644\u0627\u0628\u064A\u0629 \u0627\u0644\u062A\u064A \u062A\u062A\u0637\u0644\u0628 \u062A\u062D\u0642\u0642 .EDU",
