      adobeTitle: "Adobe Creative Cloud - \u062E\u0635\u0645 60%",
      adobeP1: "\u0627\u0644\u0633\u0639\u0631 \u0627\u0644\u0639\u0627\u062F\u064A: 59.99$/\u0634\u0647\u0631 | \u0633\u0639\u0631 \u0627\u0644\u0637\u0627\u0644\u0628: 19.99$/\u0634\u0647\u0631 | \u062A\u0648\u0641\u064A\u0631: 480$/\u0633\u0646\u0629",
