        text: "\u041D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u043D\u044B\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0438 \u043C\u043E\u0433\u0443\u0442 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u0442\u044C \u043F\u043B\u0430\u0442\u043D\u043E\u0439 \u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0438. \u0412\u0441\u0435 \u043F\u043B\u0430\u0442\u0435\u0436\u0438 \u0440\u0435\u0433\u0443\u043B\u0438\u0440\u0443\u044E\u0442\u0441\u044F \u043D\u0430\u0448\u0438\u043C\u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u044F\u043C\u0438 \u043E\u043F\u043B\u0430\u0442\u044B \u0438 \u043D\u0435 \u043F\u043E\u0434\u043B\u0435\u0436\u0430\u0442 \u0432\u043E\u0437\u0432\u0440\u0430\u0442\u0443.",
        billing: "\u0426\u0435\u043D\u044B, \u043F\u043E\u0440\u044F\u0434\u043E\u043A \u043E\u043F\u043B\u0430\u0442\u044B \u0438 \u0443\u0441\u043B\u043E\u0432\u0438\u044F \u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0438 \u0431\u0443\u0434\u0443\u0442 \u0447\u0451\u0442\u043A\u043E \u0443\u043A\u0430\u0437\u0430\u043D\u044B \u043F\u0440\u0438 \u0437\u0430\u043F\u0443\u0441\u043A\u0435 \u0441\u0435\u0440\u0432\u0438\u0441\u0430 Premium.",
