        supportService: "\u041F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u043D\u0430\u0448 \u0441\u0435\u0440\u0432\u0438\u0441",
        supportText: "\u041F\u043E\u043C\u043E\u0433\u0438\u0442\u0435 \u043D\u0430\u043C \u0441\u043E\u0445\u0440\u0430\u043D\u0438\u0442\u044C FireTempMail \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u043C, \u0441\u0434\u0435\u043B\u0430\u0432 \u043F\u043E\u0436\u0435\u0440\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435. \u0412\u0430\u0448\u0430 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u043A\u0430 \u043F\u043E\u043C\u043E\u0433\u0430\u0435\u0442 \u043D\u0430\u043C \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0442\u044C \u0440\u0430\u0431\u043E\u0442\u0443."
