    emailGeneratorPage7 = {
      h1: "Fire Temp Mail \u2014 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0439 \u0433\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B",
      lead: "\u041C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E \u0441\u043E\u0437\u0434\u0430\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 \u0430\u0434\u0440\u0435\u0441 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B. \u0417\u0430\u0449\u0438\u0442\u0438\u0442\u0435 \u0441\u0432\u043E\u0439 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u043F\u043E\u0447\u0442\u043E\u0432\u044B\u0439 \u044F\u0449\u0438\u043A \u043E\u0442 \u0441\u043F\u0430\u043C\u0430 \u0438 \u043D\u0435\u0436\u0435\u043B\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u043F\u0438\u0441\u0435\u043C.",
      seoTitle: "\u0413\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440 email \u0434\u043B\u044F \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432 \u0438 QA-\u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F",
      seoDesc: "\u041F\u0440\u043E\u0444\u0435\u0441\u0441\u0438\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u0433\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B, \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u043D\u044B\u0439 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E \u0434\u043B\u044F \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u043D\u043E\u0433\u043E \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0435\u043D\u0438\u044F, QA-\u0438\u043D\u0436\u0435\u043D\u0435\u0440\u043E\u0432 \u0438 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0441\u0442\u043E\u0432 \u043F\u043E \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0437\u0430\u0446\u0438\u0438 \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F.",
      whyTitle: "\u0417\u0430\u0447\u0435\u043C \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u0430\u043C \u043D\u0443\u0436\u043D\u0430 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0430\u044F \u043F\u043E\u0447\u0442\u0430 \u0434\u043B\u044F \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F",
      whyP1: "\u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0439, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0445 \u0441 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u043E\u0439, \u043D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E, \u043D\u043E \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u043D\u043D\u043E. \u041D\u0443\u0436\u043D\u043E \u043F\u0440\u043E\u0432\u0435\u0440\u044F\u0442\u044C \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439, \u0441\u0441\u044B\u043B\u043A\u0438 \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F, \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u0441\u0431\u0440\u043E\u0441\u0430 \u043F\u0430\u0440\u043E\u043B\u044F \u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0443\u0432\u0435\u0434\u043E\u043C\u043B\u0435\u043D\u0438\u0439 \u2014 \u043D\u043E \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435 \u0434\u0435\u0441\u044F\u0442\u043A\u043E\u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0445 email-\u0430\u043A\u043A\u0430\u0443\u043D\u0442\u043E\u0432 \u043C\u0435\u0434\u043B\u0435\u043D\u043D\u043E \u0438 \u043D\u0435\u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E.",
      whyP2: "Fire Temp Mail \u043F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u044B\u0435 \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0435 \u0430\u0434\u0440\u0435\u0441\u0430 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B, \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u043D\u043D\u044B\u0435 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u044C\u043D\u043E \u0434\u043B\u044F \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u043D\u043E\u0433\u043E \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0435\u043D\u0438\u044F. \u0413\u0435\u043D\u0435\u0440\u0438\u0440\u0443\u0439\u0442\u0435 \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 email \u0434\u043B\u044F \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u043E\u0447\u0442\u043E\u0432\u044B\u0445 \u043F\u043E\u0442\u043E\u043A\u043E\u0432 \u0432\u0430\u0448\u0435\u0433\u043E \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u044F.",
      painPointsTitle: "\u0422\u0438\u043F\u0438\u0447\u043D\u044B\u0435 \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u044B \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432 (\u0440\u0435\u0448\u0435\u043D\u044B)",
      pp1: "\u0420\u0443\u0447\u043D\u043E\u0435 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435 \u0442\u0435\u0441\u0442\u043E\u0432\u044B\u0445 \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u043E\u0432 Gmail/Outlook \u2192 \u041C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u0430\u044F \u0433\u0435\u043D\u0435\u0440\u0430\u0446\u0438\u044F \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0430 email",
      pp2: "\u0423\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043F\u0430\u0440\u043E\u043B\u044F\u043C\u0438 \u0434\u043B\u044F \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u0442\u0435\u0441\u0442\u043E\u0432\u044B\u0445 \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u043E\u0432 \u2192 \u0423\u0447\u0451\u0442\u043D\u044B\u0435 \u0434\u0430\u043D\u043D\u044B\u0435 \u043D\u0435 \u0442\u0440\u0435\u0431\u0443\u044E\u0442\u0441\u044F",
      pp3: "\u041E\u0447\u0438\u0441\u0442\u043A\u0430 \u0443\u0441\u0442\u0430\u0440\u0435\u0432\u0448\u0438\u0445 \u0442\u0435\u0441\u0442\u043E\u0432\u044B\u0445 \u0434\u0430\u043D\u043D\u044B\u0445 \u2192 \u0410\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0443\u0434\u0430\u043B\u0435\u043D\u0438\u0435 \u0447\u0435\u0440\u0435\u0437 24 \u0447\u0430\u0441\u0430",
      pp4: "\u0411\u043B\u043E\u043A\u0438\u0440\u043E\u0432\u043A\u0430 \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0439 \u043F\u043E\u0447\u0442\u043E\u0432\u044B\u043C\u0438 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u0430\u043C\u0438 \u2192 \u0420\u0435\u0430\u043B\u044C\u043D\u044B\u0435 \u0434\u043E\u043C\u0435\u043D\u044B, \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0449\u0438\u0435 \u0432\u0435\u0437\u0434\u0435",
      pp5: "\u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043C\u043D\u043E\u0433\u043E\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u0438\u0445 \u0441\u0446\u0435\u043D\u0430\u0440\u0438\u0435\u0432 \u2192 \u041D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u0445 \u0430\u0434\u0440\u0435\u0441\u043E\u0432 \u043F\u043E \u0437\u0430\u043F\u0440\u043E\u0441\u0443",
      pp6: "\u041F\u043E\u0442\u0440\u0435\u0431\u043D\u043E\u0441\u0442\u044C CI/CD-\u043F\u0430\u0439\u043F\u043B\u0430\u0439\u043D\u043E\u0432 \u0432 \u0441\u0432\u0435\u0436\u0438\u0445 email \u2192 \u0413\u0435\u043D\u0435\u0440\u0430\u0446\u0438\u044F email \u0431\u0435\u0437 \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0438",
      uc1Title: "1. \u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439 \u0438 \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F email",
      uc1P1: "\u0412\u0430\u0448\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F email \u043F\u0440\u0438 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438. \u041D\u0435\u043E\u0431\u0445\u043E\u0434\u0438\u043C\u043E \u043F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u044C, \u0447\u0442\u043E \u043F\u0438\u0441\u044C\u043C\u0430 \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0442, \u0441\u0441\u044B\u043B\u043A\u0438 \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0442 \u043A\u043E\u0440\u0440\u0435\u043A\u0442\u043D\u043E, \u0442\u043E\u043A\u0435\u043D\u044B \u0438\u0441\u0442\u0435\u043A\u0430\u044E\u0442, \u0430 \u043A\u0440\u0430\u0439\u043D\u0438\u0435 \u0441\u043B\u0443\u0447\u0430\u0438 \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u044E\u0442\u0441\u044F.",
      uc1P2: "\u0421\u0433\u0435\u043D\u0435\u0440\u0438\u0440\u0443\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 email \u2192 \u0417\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u0443\u0439\u0442\u0435\u0441\u044C \u0432 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0438 \u2192 \u041F\u0440\u043E\u0432\u0435\u0440\u044C\u0442\u0435 \u0432\u0445\u043E\u0434\u044F\u0449\u0438\u0435 \u043D\u0430 \u043D\u0430\u043B\u0438\u0447\u0438\u0435 \u043F\u0438\u0441\u044C\u043C\u0430 \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F \u2192 \u0418\u0437\u0432\u043B\u0435\u043A\u0438\u0442\u0435 \u0441\u0441\u044B\u043B\u043A\u0443/\u043A\u043E\u0434 \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F \u2192 \u0417\u0430\u0432\u0435\u0440\u0448\u0438\u0442\u0435 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044E \u2192 \u041F\u0440\u043E\u0442\u0435\u0441\u0442\u0438\u0440\u0443\u0439\u0442\u0435 \u043A\u0440\u0430\u0439\u043D\u0438\u0435 \u0441\u043B\u0443\u0447\u0430\u0438.",
      uc2Title: "2. \u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430 \u0441\u0431\u0440\u043E\u0441\u0430 \u043F\u0430\u0440\u043E\u043B\u044F",
      uc2P1: "\u0422\u0449\u0430\u0442\u0435\u043B\u044C\u043D\u043E \u043F\u0440\u043E\u0442\u0435\u0441\u0442\u0438\u0440\u0443\u0439\u0442\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u044E \u0441\u0431\u0440\u043E\u0441\u0430 \u043F\u0430\u0440\u043E\u043B\u044F, \u0441\u043E\u0437\u0434\u0430\u0432 \u0442\u0435\u0441\u0442\u043E\u0432\u044B\u0435 \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u044B \u0441 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u043E\u0439 \u0438 \u0437\u0430\u043F\u0443\u0441\u0442\u0438\u0432 \u043F\u0440\u043E\u0446\u0435\u0441\u0441 \u0432\u043E\u0441\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u0430\u0440\u043E\u043B\u044F \u0434\u043B\u044F \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u043F\u0438\u0441\u0435\u043C \u0441\u0431\u0440\u043E\u0441\u0430.",
      uc2P2: "\u0412\u0430\u043B\u0438\u0434\u043D\u044B\u0435 \u0437\u0430\u043F\u0440\u043E\u0441\u044B \u043D\u0430 \u0441\u0431\u0440\u043E\u0441, \u043F\u0440\u043E\u0441\u0440\u043E\u0447\u0435\u043D\u043D\u044B\u0435 \u0442\u043E\u043A\u0435\u043D\u044B, \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u043F\u043E\u043F\u044B\u0442\u043A\u0438 \u0441\u0431\u0440\u043E\u0441\u0430, \u043D\u0435\u0432\u0435\u0440\u043D\u044B\u0435 email-\u0430\u0434\u0440\u0435\u0441\u0430, \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435 \u0447\u0430\u0441\u0442\u043E\u0442\u044B \u0437\u0430\u043F\u0440\u043E\u0441\u043E\u0432 \u0438 \u043A\u0440\u043E\u0441\u0441\u0430\u043A\u043A\u0430\u0443\u043D\u0442\u043D\u0430\u044F \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u044C.",
      uc3Title: "3. \u041C\u043D\u043E\u0433\u043E\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u043E\u0435 \u0438 \u0440\u043E\u043B\u0435\u0432\u043E\u0435 \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435",
      uc3P1: "\u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0439 \u0441 \u0440\u0430\u0437\u043D\u044B\u043C\u0438 \u0440\u043E\u043B\u044F\u043C\u0438 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439 (\u0430\u0434\u043C\u0438\u043D\u0438\u0441\u0442\u0440\u0430\u0442\u043E\u0440, \u043C\u043E\u0434\u0435\u0440\u0430\u0442\u043E\u0440, \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C) \u0438\u043B\u0438 \u043C\u0443\u043B\u044C\u0442\u0438\u0442\u0435\u043D\u0430\u043D\u0442\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0430 \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u0445 \u0430\u0434\u0440\u0435\u0441\u043E\u0432 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B.",
      uc4Title: "4. \u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B email-\u0443\u0432\u0435\u0434\u043E\u043C\u043B\u0435\u043D\u0438\u0439",
      uc4P1: "\u0415\u0441\u043B\u0438 \u0432\u0430\u0448\u0435 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u043E\u0442\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u0442\u0440\u0430\u043D\u0437\u0430\u043A\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u043F\u0438\u0441\u044C\u043C\u0430 (\u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F \u0437\u0430\u043A\u0430\u0437\u043E\u0432, \u043E\u043F\u043E\u0432\u0435\u0449\u0435\u043D\u0438\u044F, \u043D\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F), \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0443\u044E \u043F\u043E\u0447\u0442\u0443 \u0434\u043B\u044F \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0438 \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0441\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u043D\u0438\u044F \u0441\u043E\u0431\u044B\u0442\u0438\u0439.",
      uc5Title: "5. \u0410\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044F \u0441 CI/CD",
      uc5P1: "\u0412\u0430\u0448 CI/CD-\u043F\u0430\u0439\u043F\u043B\u0430\u0439\u043D \u0437\u0430\u043F\u0443\u0441\u043A\u0430\u0435\u0442 \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0435 E2E-\u0442\u0435\u0441\u0442\u044B, \u0432\u043A\u043B\u044E\u0447\u0430\u044E\u0449\u0438\u0435 \u0440\u0430\u0431\u043E\u0447\u0438\u0435 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u0441 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u043E\u0439. \u0414\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0437\u0430\u043F\u0443\u0441\u043A\u0430 \u0442\u0435\u0441\u0442\u043E\u0432 \u043D\u0443\u0436\u043D\u044B \u0441\u0432\u0435\u0436\u0438\u0435 \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u0435 email-\u0430\u0434\u0440\u0435\u0441\u0430.",
      uc5P2: "\u0413\u0435\u043D\u0435\u0440\u0438\u0440\u0443\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 email \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u043D\u043E \u0438\u043B\u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u0441\u043E\u0433\u043B\u0430\u0441\u043E\u0432\u0430\u043D\u043D\u044B\u0435 \u0448\u0430\u0431\u043B\u043E\u043D\u044B \u0438\u043C\u0435\u043D\u043E\u0432\u0430\u043D\u0438\u044F \u0434\u043B\u044F \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u0445 \u0430\u0434\u0440\u0435\u0441\u043E\u0432 \u0434\u043B\u044F \u043A\u0430\u0436\u0434\u043E\u0433\u043E \u0437\u0430\u043F\u0443\u0441\u043A\u0430 \u0442\u0435\u0441\u0442\u043E\u0432. \u0418\u0434\u0435\u0430\u043B\u044C\u043D\u043E \u043F\u043E\u0434\u0445\u043E\u0434\u0438\u0442 \u0434\u043B\u044F \u0442\u0435\u0441\u0442\u043E\u0432\u044B\u0445 \u043D\u0430\u0431\u043E\u0440\u043E\u0432 Playwright, Cypress \u0438 Selenium.",
      uc6Title: "6. \u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0441\u043E \u0441\u0442\u043E\u0440\u043E\u043D\u043D\u0438\u043C\u0438 email-\u0441\u0435\u0440\u0432\u0438\u0441\u0430\u043C\u0438",
      uc6P1: "\u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 \u0441 SendGrid, Mailgun, AWS SES, Postmark \u0438\u043B\u0438 \u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u043F\u043E\u0441\u0442\u0430\u0432\u0449\u0438\u043A\u0430\u043C\u0438 email-\u0443\u0441\u043B\u0443\u0433 \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0445 \u0430\u0434\u0440\u0435\u0441\u043E\u0432 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u0435\u0439 \u0434\u043B\u044F \u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0438 \u0443\u0441\u043F\u0435\u0448\u043D\u043E\u0439 \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0438 \u043F\u0438\u0441\u0435\u043C.",
      featuresTitle: "\u0424\u0443\u043D\u043A\u0446\u0438\u0438 \u0434\u043B\u044F \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432",
      f1: "\u0411\u0435\u0437 \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0438: \u043D\u0438\u043A\u0430\u043A\u0438\u0445 API-\u043A\u043B\u044E\u0447\u0435\u0439, \u0430\u0443\u0442\u0435\u043D\u0442\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438 \u0438\u043B\u0438 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u0430. \u041E\u0442\u043A\u0440\u043E\u0439\u0442\u0435 \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0443, \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u0435 email-\u0430\u0434\u0440\u0435\u0441 \u0438 \u043D\u0430\u0447\u043D\u0438\u0442\u0435 \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435.",
      f2: "\u041F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u0435 \u043F\u0438\u0441\u0435\u043C \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438: \u043F\u0438\u0441\u044C\u043C\u0430 \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0432\u043E \u0432\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u0437\u0430 \u0441\u0435\u043A\u0443\u043D\u0434\u044B. \u0411\u0435\u0437 \u0437\u0430\u0434\u0435\u0440\u0436\u0435\u043A \u043E\u043F\u0440\u043E\u0441\u0430 \u0438 \u043F\u0430\u043A\u0435\u0442\u043D\u043E\u0439 \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0438.",
      f3: "\u041F\u043E\u043B\u043D\u044B\u0439 \u0434\u043E\u0441\u0442\u0443\u043F \u043A \u043F\u0438\u0441\u044C\u043C\u0430\u043C: \u043F\u0440\u043E\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0439\u0442\u0435 \u043F\u043E\u043B\u043D\u043E\u0435 \u0441\u043E\u0434\u0435\u0440\u0436\u0438\u043C\u043E\u0435 \u043F\u0438\u0441\u044C\u043C\u0430, \u0432\u043A\u043B\u044E\u0447\u0430\u044F HTML-\u0442\u0435\u043B\u043E, \u043F\u0440\u043E\u0441\u0442\u043E\u0439 \u0442\u0435\u043A\u0441\u0442, \u0437\u0430\u0433\u043E\u043B\u043E\u0432\u043A\u0438, \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u044E \u043E\u0431 \u043E\u0442\u043F\u0440\u0430\u0432\u0438\u0442\u0435\u043B\u0435 \u0438 \u0432\u043B\u043E\u0436\u0435\u043D\u0438\u044F.",
      f4: "\u041F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u0438\u0435 \u043F\u0441\u0435\u0432\u0434\u043E\u043D\u0438\u043C\u044B \u0434\u043B\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438: \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u043E\u043F\u0438\u0441\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 email-\u0430\u0434\u0440\u0435\u0441\u0430, \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0435 \u043A \u043A\u043E\u043D\u043A\u0440\u0435\u0442\u043D\u044B\u043C \u0442\u0435\u0441\u0442\u043E\u0432\u044B\u043C \u0441\u043B\u0443\u0447\u0430\u044F\u043C.",
      f5: "\u0410\u0432\u0442\u043E\u043E\u0447\u0438\u0441\u0442\u043A\u0430: \u043F\u0438\u0441\u044C\u043C\u0430 \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0443\u0434\u0430\u043B\u044F\u044E\u0442\u0441\u044F \u0447\u0435\u0440\u0435\u0437 24 \u0447\u0430\u0441\u0430. \u041D\u0438\u043A\u0430\u043A\u043E\u0439 \u0440\u0443\u0447\u043D\u043E\u0439 \u043E\u0447\u0438\u0441\u0442\u043A\u0438, \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0443\u0447\u0451\u0442\u043D\u044B\u043C\u0438 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u0438 \u043D\u0430\u043A\u043B\u0430\u0434\u043D\u044B\u0445 \u0440\u0430\u0441\u0445\u043E\u0434\u043E\u0432 \u043D\u0430 \u043E\u0431\u0441\u043B\u0443\u0436\u0438\u0432\u0430\u043D\u0438\u0435.",
      securityTitle: "\u041D\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u0435 \u043E \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438 \u0434\u043B\u044F \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432",
      securityWarn: "\u0412\u0440\u0435\u043C\u0435\u043D\u043D\u0430\u044F \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u0430\u044F \u043F\u043E\u0447\u0442\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0443\u0431\u043B\u0438\u0447\u043D\u043E\u0439 \u0438 \u043D\u0435\u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0439. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u0441\u0440\u0435\u0434\u0430\u0445 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0438 \u0438 QA-\u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0441 \u0442\u0435\u0441\u0442\u043E\u0432\u044B\u043C\u0438 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u0438 \u0438\u0437\u043E\u043B\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u043C\u0438 \u0442\u0435\u0441\u0442\u043E\u0432\u044B\u043C\u0438 \u0431\u0430\u0437\u0430\u043C\u0438 \u0434\u0430\u043D\u043D\u044B\u0445.",
      securityNever: "\u041D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0443\u044E \u043F\u043E\u0447\u0442\u0443 \u0434\u043B\u044F: \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0441\u0438\u0441\u0442\u0435\u043C, \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0445 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u0438\u0445 \u0434\u0430\u043D\u043D\u044B\u0445, \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u043B\u0430\u0442\u0435\u0436\u0435\u0439, \u043A\u043E\u043D\u0444\u0438\u0434\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438 \u0438\u043B\u0438 \u0443\u0447\u0451\u0442\u043D\u044B\u0445 \u0434\u0430\u043D\u043D\u044B\u0445 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 \u0431\u0430\u0437 \u0434\u0430\u043D\u043D\u044B\u0445.",
      startTitle: "\u041D\u0430\u0447\u043D\u0438\u0442\u0435 \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u044F\u043C\u043E \u0441\u0435\u0439\u0447\u0430\u0441",
      startP1: "\u041F\u0435\u0440\u0435\u0441\u0442\u0430\u043D\u044C\u0442\u0435 \u0442\u0440\u0430\u0442\u0438\u0442\u044C \u0432\u0440\u0435\u043C\u044F \u043D\u0430 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0442\u0435\u0441\u0442\u043E\u0432\u044B\u043C\u0438 email-\u0430\u043A\u043A\u0430\u0443\u043D\u0442\u0430\u043C\u0438. \u0413\u0435\u043D\u0435\u0440\u0438\u0440\u0443\u0439\u0442\u0435 \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0445 \u0430\u0434\u0440\u0435\u0441\u043E\u0432 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E \u0438 \u0441\u043E\u0441\u0440\u0435\u0434\u043E\u0442\u043E\u0447\u044C\u0442\u0435\u0441\u044C \u043D\u0430 \u0433\u043B\u0430\u0432\u043D\u043E\u043C \u2014 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0438 \u0438 \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0438 \u043E\u0442\u043B\u0438\u0447\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u043D\u043E\u0433\u043E \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0435\u043D\u0438\u044F.",
      startP2: "\u0424\u0440\u043E\u043D\u0442\u0435\u043D\u0434-\u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u0438, \u0431\u044D\u043A\u0435\u043D\u0434-\u0438\u043D\u0436\u0435\u043D\u0435\u0440\u044B, QA-\u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0449\u0438\u043A\u0438, DevOps-\u0438\u043D\u0436\u0435\u043D\u0435\u0440\u044B, \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0441\u0442\u044B \u043F\u043E \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0437\u0430\u0446\u0438\u0438 \u0438 \u0432\u0441\u0435, \u043A\u0442\u043E \u0441\u043E\u0437\u0434\u0430\u0451\u0442 \u0444\u0443\u043D\u043A\u0446\u0438\u0438, \u0437\u0430\u0432\u0438\u0441\u044F\u0449\u0438\u0435 \u043E\u0442 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B."
    };
    tempGmailPage7 = {
      h1: "Temp Gmail \u2014 \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 \u0430\u0434\u0440\u0435\u0441\u0430 Gmail",
      lead: "\u041C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 \u0430\u0434\u0440\u0435\u0441\u0430 Gmail, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u044B\u0433\u043B\u044F\u0434\u044F\u0442 \u0438 \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0442 \u043A\u0430\u043A \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u0435 \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u044B Gmail. \u0417\u0430\u0449\u0438\u0442\u0438\u0442\u0435 \u043B\u0438\u0447\u043D\u044B\u0439 \u043F\u043E\u0447\u0442\u043E\u0432\u044B\u0439 \u044F\u0449\u0438\u043A \u043E\u0442 \u0441\u043F\u0430\u043C\u0430.",
      seoTitle1: "\u0421\u043A\u0440\u044B\u0442\u044B\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0438 \u043A\u043E\u043D\u0444\u0438\u0434\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 Gmail: \u043F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u044F \u0438 \u0442\u0440\u044E\u043A \u0441 \u0442\u043E\u0447\u043A\u043E\u0439",
      seoP1: "\u0417\u043D\u0430\u0435\u0442\u0435 \u043B\u0438 \u0432\u044B, \u0447\u0442\u043E \u0432\u0430\u0448 \u0430\u043A\u043A\u0430\u0443\u043D\u0442 Gmail \u043C\u043E\u0436\u0435\u0442 \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0442\u044C \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E email-\u0430\u0434\u0440\u0435\u0441\u043E\u0432 \u0431\u0435\u0437 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u043D\u043E\u0432\u044B\u0445 \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u043E\u0432? \u0423 Gmail \u0435\u0441\u0442\u044C \u0434\u0432\u0435 \u043C\u043E\u0449\u043D\u044B\u0435 \u0432\u0441\u0442\u0440\u043E\u0435\u043D\u043D\u044B\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0438, \u043E \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439 \u043D\u0435 \u0437\u043D\u0430\u044E\u0442.",
      seoP2: "\u042D\u0442\u043E \u043D\u0435 \xAB\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 email\xBB \u043E\u0442 \u0441\u0442\u043E\u0440\u043E\u043D\u043D\u0435\u0433\u043E \u0441\u0435\u0440\u0432\u0438\u0441\u0430 \u2014 \u044D\u0442\u043E \u0437\u0430\u043A\u043E\u043D\u043D\u044B\u0435 \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0438 \u0432\u0430\u0448\u0435\u0433\u043E \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0430\u0434\u0440\u0435\u0441\u0430 Gmail, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u0440\u044F\u043C\u043E \u0432 \u0432\u0430\u0448 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u0439 \u043F\u043E\u0447\u0442\u043E\u0432\u044B\u0439 \u044F\u0449\u0438\u043A.",
      plusTitle: "\u041F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u044F Gmail (\u0442\u0440\u044E\u043A \u0441 \xAB+\xBB)",
      plusP1: "Gmail \u0438\u0433\u043D\u043E\u0440\u0438\u0440\u0443\u0435\u0442 \u0432\u0441\u0451, \u0447\u0442\u043E \u0438\u0434\u0451\u0442 \u043F\u043E\u0441\u043B\u0435 \u0437\u043D\u0430\u043A\u0430 \xAB\u043F\u043B\u044E\u0441\xBB (+) \u0432 \u0432\u0430\u0448\u0435\u043C \u0430\u0434\u0440\u0435\u0441\u0435 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B.",
      plusL1: "john.smith+shopping@gmail.com \u2014 \u0434\u043B\u044F \u0438\u043D\u0442\u0435\u0440\u043D\u0435\u0442-\u043C\u0430\u0433\u0430\u0437\u0438\u043D\u043E\u0432",
      plusL2: "john.smith+newsletters@gmail.com \u2014 \u0434\u043B\u044F \u043F\u043E\u0434\u043F\u0438\u0441\u043E\u043A \u043D\u0430 \u0440\u0430\u0441\u0441\u044B\u043B\u043A\u0438",
      plusL3: "john.smith+facebook@gmail.com \u2014 \u0434\u043B\u044F \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u0432 Facebook",
      plusL4: "john.smith+netflix@gmail.com \u2014 \u0434\u043B\u044F \u043F\u0440\u043E\u0431\u043D\u043E\u0439 \u0432\u0435\u0440\u0441\u0438\u0438 Netflix",
      plusL5: "john.smith+spam@gmail.com \u2014 \u0434\u043B\u044F \u043D\u0435\u043D\u0430\u0434\u0451\u0436\u043D\u044B\u0445 \u0441\u0430\u0439\u0442\u043E\u0432",
      whyPlusTitle: "\u041F\u043E\u0447\u0435\u043C\u0443 \u043F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u044F \u2014 \u044D\u0442\u043E \u043C\u043E\u0449\u043D\u044B\u0439 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442",
      whyPlusP1: "1. \u041E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0434\u0430\u0432\u0446\u043E\u0432 email: \u0435\u0441\u043B\u0438 \u0432\u044B \u0437\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u0443\u0435\u0442\u0435\u0441\u044C \u043D\u0430 \u0441\u0435\u0440\u0432\u0438\u0441\u0435 \u0441 \u0430\u0434\u0440\u0435\u0441\u043E\u043C yourname+serviceX@gmail.com \u0438 \u043D\u0430\u0447\u043D\u0451\u0442\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u044C \u0441\u043F\u0430\u043C, \u0432\u044B \u0442\u043E\u0447\u043D\u043E \u0431\u0443\u0434\u0435\u0442\u0435 \u0437\u043D\u0430\u0442\u044C, \u043A\u0442\u043E \u043F\u0440\u043E\u0434\u0430\u043B \u0432\u0430\u0448 email.",
      whyPlusP2: "2. \u0410\u0432\u0442\u043E\u0444\u0438\u043B\u044C\u0442\u0440\u0430\u0446\u0438\u044F: \u0441\u043E\u0437\u0434\u0430\u0439\u0442\u0435 \u0444\u0438\u043B\u044C\u0442\u0440\u044B Gmail \u043D\u0430 \u043E\u0441\u043D\u043E\u0432\u0435 \u0442\u0435\u0433\u0430 \xAB+\xBB \u0434\u043B\u044F \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0441\u043E\u0440\u0442\u0438\u0440\u043E\u0432\u043A\u0438 \u043F\u0438\u0441\u0435\u043C \u043F\u043E \u043F\u0430\u043F\u043A\u0430\u043C.",
      whyPlusP3: "3. \u041E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044F \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0439: \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u0440\u0430\u0437\u043D\u044B\u0435 \u0442\u0435\u0433\u0438 \u0434\u043B\u044F \u0440\u0430\u0437\u043D\u044B\u0445 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0439: +work, +personal, +testing, +shopping.",
      whyPlusP4: "4. \u041E\u0440\u0433\u0430\u043D\u0438\u0437\u0443\u0439\u0442\u0435 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u043F\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0443: \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0435\u0440\u0432\u0438\u0441\u044B \u0438 \u0440\u0430\u0441\u0441\u044B\u043B\u043A\u0438 \u043E\u0442\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0442 \u043C\u043D\u043E\u0433\u043E follow-up \u043F\u0438\u0441\u0435\u043C. Plus-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u044F \u043F\u043E\u043C\u043E\u0433\u0430\u0435\u0442 \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0442\u044C \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0438.",
      dotTitle: "\u0422\u0440\u044E\u043A \u0441 \u0442\u043E\u0447\u043A\u043E\u0439 \u0432 Gmail: \u0440\u0430\u0441\u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435 \u0442\u043E\u0447\u0435\u043A \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u044F",
      dotP1: "Gmail \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0438\u0433\u043D\u043E\u0440\u0438\u0440\u0443\u0435\u0442 \u0442\u043E\u0447\u043A\u0438 \u0432 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u043E\u0439 \u0447\u0430\u0441\u0442\u0438 \u0432\u0430\u0448\u0435\u0433\u043E \u0430\u0434\u0440\u0435\u0441\u0430 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B.",
      dotUseTitle: "\u041A\u0430\u043A \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u0442\u0440\u044E\u043A \u0441 \u0442\u043E\u0447\u043A\u043E\u0439",
      dotUseP1: "\u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u0430\u043B\u0438\u0430\u0441\u043E\u0432 \u0438 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u044F: \u0432\u0430\u0440\u0438\u0430\u043D\u0442\u044B \u0441 \u0442\u043E\u0447\u043A\u0430\u043C\u0438 \u043F\u043E\u043C\u043E\u0433\u0430\u044E\u0442 \u043F\u0440\u043E\u0432\u0435\u0440\u0438\u0442\u044C \u043D\u043E\u0440\u043C\u0430\u043B\u0438\u0437\u0430\u0446\u0438\u044E Gmail, \u043F\u0440\u0438 \u044D\u0442\u043E\u043C \u0432\u0441\u0435 \u043F\u0438\u0441\u044C\u043C\u0430 \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0442 \u0432 \u043E\u0434\u0438\u043D \u044F\u0449\u0438\u043A.",
      combineTitle: "\u041A\u043E\u043C\u0431\u0438\u043D\u0430\u0446\u0438\u044F \u043F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u0438 \u0438 \u0442\u0440\u044E\u043A\u0430 \u0441 \u0442\u043E\u0447\u043A\u043E\u0439",
      combineP1: "\u0414\u043B\u044F \u043C\u0430\u043A\u0441\u0438\u043C\u0430\u043B\u044C\u043D\u043E\u0439 \u0433\u0438\u0431\u043A\u043E\u0441\u0442\u0438 \u043A\u043E\u043C\u0431\u0438\u043D\u0438\u0440\u0443\u0439\u0442\u0435 \u043E\u0431\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0438: j.o.h.n.smith+netflix@gmail.com. \u042D\u0442\u043E \u0441\u043E\u0437\u0434\u0430\u0451\u0442 \u043F\u0440\u0430\u043A\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u0447\u0438\u0441\u043B\u043E \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u0445 \u0430\u0434\u0440\u0435\u0441\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u0441\u0435 \u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0432 \u043E\u0434\u0438\u043D \u043F\u043E\u0447\u0442\u043E\u0432\u044B\u0439 \u044F\u0449\u0438\u043A Gmail.",
      breachTitle: "\u0420\u0435\u0430\u043B\u044C\u043D\u044B\u0439 \u043F\u0440\u0438\u043C\u0435\u0440: \u043E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u0443\u0442\u0435\u0447\u0435\u043A \u0434\u0430\u043D\u043D\u044B\u0445",
      breachP1: "\u0414\u043E\u043F\u0443\u0441\u0442\u0438\u043C, \u0432\u044B \u0437\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043B\u0438\u0441\u044C \u0432 \xABShoppingAppX\xBB \u0441 \u0430\u0434\u0440\u0435\u0441\u043E\u043C yourname+shoppingappx@gmail.com. \u0427\u0435\u0440\u0435\u0437 \u0448\u0435\u0441\u0442\u044C \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0432\u044B \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u044C \u0441\u043F\u0430\u043C \u043D\u0430 \u044D\u0442\u043E\u0442 \u0430\u0434\u0440\u0435\u0441.",
      breachL1: "\u041F\u0440\u043E\u0434\u0430\u043B\u0438 \u0432\u0430\u0448 email \u043C\u0430\u0440\u043A\u0435\u0442\u043E\u043B\u043E\u0433\u0430\u043C",
      breachL2: "\u0421\u0442\u0430\u043B\u0438 \u0436\u0435\u0440\u0442\u0432\u043E\u0439 \u0443\u0442\u0435\u0447\u043A\u0438 \u0434\u0430\u043D\u043D\u044B\u0445",
      breachL3: "\u0414\u0435\u043B\u044F\u0442\u0441\u044F email \u0441 \xAB\u043F\u0430\u0440\u0442\u043D\u0451\u0440\u0430\u043C\u0438\xBB",
      breachP2: "\u0422\u0435\u043F\u0435\u0440\u044C \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u0441\u043E\u0437\u0434\u0430\u0442\u044C \u0444\u0438\u043B\u044C\u0442\u0440 Gmail \u0434\u043B\u044F \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0443\u0434\u0430\u043B\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u0433\u043E, \u0447\u0442\u043E \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u043D\u0430 \u044D\u0442\u043E\u0442 \u0430\u0434\u0440\u0435\u0441, \u044D\u0444\u0444\u0435\u043A\u0442\u0438\u0432\u043D\u043E \u0431\u043B\u043E\u043A\u0438\u0440\u0443\u044F \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A \u0441\u043F\u0430\u043C\u0430.",
      filterTitle: "\u041A\u0430\u043A \u043D\u0430\u0441\u0442\u0440\u043E\u0438\u0442\u044C \u0444\u0438\u043B\u044C\u0442\u0440\u044B Gmail \u0434\u043B\u044F \u043F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u0438",
      filterP1: "\u041D\u0430\u0447\u0430\u0432 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u043F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u044E, \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0443\u0439\u0442\u0435 \u0432\u0445\u043E\u0434\u044F\u0449\u0443\u044E \u043F\u043E\u0447\u0442\u0443 \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438:",
      filterL1: "\u041E\u0442\u043A\u0440\u043E\u0439\u0442\u0435 \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0438 Gmail: \u043D\u0430\u0436\u043C\u0438\u0442\u0435 \u043D\u0430 \u0437\u043D\u0430\u0447\u043E\u043A \u0448\u0435\u0441\u0442\u0435\u0440\u0451\u043D\u043A\u0438 \u2192 \xAB\u0412\u0441\u0435 \u043D\u0430\u0441\u0442\u0440\u043E\u0439\u043A\u0438\xBB",
      filterL2: "\u041F\u0435\u0440\u0435\u0439\u0434\u0438\u0442\u0435 \u0432 \xAB\u0424\u0438\u043B\u044C\u0442\u0440\u044B \u0438 \u0437\u0430\u0431\u043B\u043E\u043A\u0438\u0440\u043E\u0432\u0430\u043D\u043D\u044B\u0435 \u0430\u0434\u0440\u0435\u0441\u0430\xBB: \u043D\u0430\u0436\u043C\u0438\u0442\u0435 \xAB\u0421\u043E\u0437\u0434\u0430\u0442\u044C \u043D\u043E\u0432\u044B\u0439 \u0444\u0438\u043B\u044C\u0442\u0440\xBB",
      filterL3: "\u0414\u043E\u0431\u0430\u0432\u044C\u0442\u0435 \u043F\u0440\u0430\u0432\u0438\u043B\u043E \u0444\u0438\u043B\u044C\u0442\u0440\u0430: \u0432 \u043F\u043E\u043B\u0435 \xAB\u041A\u043E\u043C\u0443\xBB \u0432\u0432\u0435\u0434\u0438\u0442\u0435 yourname+shopping@gmail.com",
      filterL4: "\u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435: \u043F\u0440\u0438\u043C\u0435\u043D\u0438\u0442\u044C \u044F\u0440\u043B\u044B\u043A, \u043F\u0440\u043E\u043F\u0443\u0441\u0442\u0438\u0442\u044C \u0432\u0445\u043E\u0434\u044F\u0449\u0438\u0435, \u043F\u043E\u043C\u0435\u0442\u0438\u0442\u044C \u043A\u0430\u043A \u043F\u0440\u043E\u0447\u0438\u0442\u0430\u043D\u043D\u043E\u0435, \u043F\u0435\u0440\u0435\u0441\u043B\u0430\u0442\u044C \u0438\u043B\u0438 \u0443\u0434\u0430\u043B\u0438\u0442\u044C",
      filterL5: "\u0421\u043E\u0445\u0440\u0430\u043D\u0438\u0442\u0435 \u0444\u0438\u043B\u044C\u0442\u0440: \u043D\u0430\u0436\u043C\u0438\u0442\u0435 \xAB\u0421\u043E\u0437\u0434\u0430\u0442\u044C \u0444\u0438\u043B\u044C\u0442\u0440\xBB \u2014 \u0433\u043E\u0442\u043E\u0432\u043E",
      filterP2: "\u0422\u0435\u043F\u0435\u0440\u044C \u043A\u0430\u0436\u0434\u043E\u0435 \u043F\u0438\u0441\u044C\u043C\u043E, \u043E\u0442\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0435 \u043D\u0430 \u044D\u0442\u043E\u0442 \u0430\u0434\u0440\u0435\u0441, \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0443\u0435\u0442\u0441\u044F \u043F\u043E \u0432\u0430\u0448\u0438\u043C \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u043C.",
      limitTitle: "\u041E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F \u0432\u0441\u0442\u0440\u043E\u0435\u043D\u043D\u044B\u0445 \u0444\u0443\u043D\u043A\u0446\u0438\u0439 Gmail",
      limitP1: "\u041D\u0435\u0441\u043C\u043E\u0442\u0440\u044F \u043D\u0430 \u043C\u043E\u0449\u043D\u043E\u0441\u0442\u044C, \u043F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u044F \u0438 \u0442\u0440\u044E\u043A \u0441 \u0442\u043E\u0447\u043A\u043E\u0439 \u0438\u043C\u0435\u044E\u0442 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u044F:",
      limitL1: "\u041D\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0430\u043D\u043E\u043D\u0438\u043C\u043D\u043E: \u0432\u0430\u0448 \u0431\u0430\u0437\u043E\u0432\u044B\u0439 \u0430\u0434\u0440\u0435\u0441 Gmail \u0432\u0441\u0451 \u0435\u0449\u0451 \u0432\u0438\u0434\u0435\u043D.",
      limitL2: "\u041D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0441\u0430\u0439\u0442\u044B \u0431\u043B\u043E\u043A\u0438\u0440\u0443\u044E\u0442 +: \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u0435\u0431-\u0441\u0430\u0439\u0442\u044B \u043E\u0442\u043A\u043B\u043E\u043D\u044F\u044E\u0442 \u0430\u0434\u0440\u0435\u0441\u0430, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0438\u0435 \u0441\u0438\u043C\u0432\u043E\u043B \xAB+\xBB.",
      limitL3: "\u041D\u0435\u0442 \u0437\u0430\u0449\u0438\u0442\u044B \u043E\u0442 Google: Google \u0432\u0441\u0451 \u0440\u0430\u0432\u043D\u043E \u0432\u0438\u0434\u0438\u0442 \u0432\u0441\u044E \u0432\u0430\u0448\u0443 \u0430\u043A\u0442\u0438\u0432\u043D\u043E\u0441\u0442\u044C.",
      limitL4: "\u041D\u0435\u043B\u044C\u0437\u044F \u0443\u0434\u0430\u043B\u0438\u0442\u044C \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u0435 \u043F\u0441\u0435\u0432\u0434\u043E\u043D\u0438\u043C\u044B: \u0432 \u043E\u0442\u043B\u0438\u0447\u0438\u0435 \u043E\u0442 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0439 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B.",
      limitL5: "\u041D\u0435 \u0434\u043B\u044F \u0440\u0438\u0441\u043A\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0439: \u0442\u0430\u043A \u043A\u0430\u043A \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0439 Gmail \u0442\u0435\u0445\u043D\u0438\u0447\u0435\u0441\u043A\u0438 \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u0434\u043E\u0441\u0442\u0443\u043F\u043D\u044B\u043C. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 Fire Temp Mail \u0432\u043C\u0435\u0441\u0442\u043E \u044D\u0442\u043E\u0433\u043E.",
      vsTitle: "\u041A\u043E\u0433\u0434\u0430 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u0442\u0440\u044E\u043A\u0438 Gmail, \u0430 \u043A\u043E\u0433\u0434\u0430 \u2014 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u0443\u044E \u043F\u043E\u0447\u0442\u0443",
      useGmailTitle: "\u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u043F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u044E/\u0442\u0440\u044E\u043A \u0441 \u0442\u043E\u0447\u043A\u043E\u0439 Gmail, \u043A\u043E\u0433\u0434\u0430:",
      useGmailL1: "\u0412\u044B \u0445\u043E\u0442\u0438\u0442\u0435 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u044C \u043F\u043E\u0447\u0442\u0443 \u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u044F\u0449\u0438\u043A",
      useGmailL2: "\u0412\u0430\u043C \u043D\u0443\u0436\u043D\u043E \u043E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u0442\u044C, \u043A\u0430\u043A\u0438\u0435 \u0441\u0435\u0440\u0432\u0438\u0441\u044B \u0434\u0435\u043B\u044F\u0442\u0441\u044F/\u043F\u0440\u043E\u0434\u0430\u044E\u0442 \u0432\u0430\u0448 email",
      useGmailL3: "\u0412\u044B \u0445\u043E\u0442\u0438\u0442\u0435 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u043E\u0432\u0430\u0442\u044C \u043F\u043E\u0447\u0442\u0443 \u0438\u0437 \u0440\u0430\u0437\u043D\u044B\u0445 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u0432",
      useGmailL4: "\u0421\u0435\u0440\u0432\u0438\u0441 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u043D\u0430\u0434\u0451\u0436\u043D\u044B\u0439, \u043D\u043E \u0433\u0435\u043D\u0435\u0440\u0438\u0440\u0443\u0435\u0442 \u0441\u043F\u0430\u043C",
      useGmailL5: "\u0412\u0430\u043C \u043C\u043E\u0436\u0435\u0442 \u043F\u043E\u043D\u0430\u0434\u043E\u0431\u0438\u0442\u044C\u0441\u044F \u0434\u043E\u043B\u0433\u043E\u0441\u0440\u043E\u0447\u043D\u044B\u0439 \u0434\u043E\u0441\u0442\u0443\u043F \u043A \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u0443",
      useDispTitle: "\u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u0443\u044E \u043F\u043E\u0447\u0442\u0443 Fire Temp Mail, \u043A\u043E\u0433\u0434\u0430:",
      useDispL1: "\u0412\u0430\u043C \u043D\u0443\u0436\u043D\u0430 \u043F\u043E\u043B\u043D\u0430\u044F \u0430\u043D\u043E\u043D\u0438\u043C\u043D\u043E\u0441\u0442\u044C (\u0431\u0435\u0437 \u0441\u0432\u044F\u0437\u0438 \u0441 \u0432\u0430\u0448\u0438\u043C \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C email)",
      useDispL2: "\u0420\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u044F \u043D\u0430 \u043D\u0435\u043D\u0430\u0434\u0451\u0436\u043D\u044B\u0445 \u0438\u043B\u0438 \u0440\u0438\u0441\u043A\u043E\u0432\u0430\u043D\u043D\u044B\u0445 \u0441\u0430\u0439\u0442\u0430\u0445",
      useDispL3: "\u041E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0435 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u0430\u043C \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u043F\u043E\u043D\u0430\u0434\u043E\u0431\u044F\u0442\u0441\u044F",
      useDispL4: "\u0422\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u0438 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0435 \u0431\u0435\u0437 \u0437\u0430\u0441\u043E\u0440\u0435\u043D\u0438\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u044F\u0449\u0438\u043A\u0430",
      useDispL5: "\u0421\u0435\u0440\u0432\u0438\u0441\u044B, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043C\u043E\u0433\u0443\u0442 \u0433\u0435\u043D\u0435\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043C\u043D\u043E\u0433\u043E \u0441\u043F\u0430\u043C\u0430 \u0438\u043B\u0438 \u0430\u0433\u0440\u0435\u0441\u0441\u0438\u0432\u043D\u043E \u043F\u0440\u043E\u0434\u0430\u0432\u0430\u0442\u044C \u0434\u0430\u043D\u043D\u044B\u0435",
      tipsTitle: "\u0421\u043E\u0432\u0435\u0442\u044B \u043F\u043E \u043A\u043E\u043D\u0444\u0438\u0434\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 Gmail \u0438 \u043F\u0440\u043E\u0434\u0432\u0438\u043D\u0443\u0442\u044B\u0435 \u0442\u0435\u0445\u043D\u0438\u043A\u0438",
      tip1Title: "1. \u0421\u043E\u0437\u0434\u0430\u043D\u0438\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \xAB\u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0445\xBB \u0444\u0438\u043B\u044C\u0442\u0440\u043E\u0432 \u0432 Gmail",
      tip1P1: "\u0421\u043E\u0437\u0434\u0430\u0439\u0442\u0435 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u0438\u0439 \u0444\u0438\u043B\u044C\u0442\u0440 \u0434\u043B\u044F \u0432\u0441\u0435\u0445 \u043F\u0438\u0441\u0435\u043C \u0441 \u043F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u0435\u0439:",
      tip1L1: "\u0423\u0441\u043B\u043E\u0432\u0438\u0435 \u0444\u0438\u043B\u044C\u0442\u0440\u0430: to:yourname+*@gmail.com",
      tip1L2: "\u0414\u0435\u0439\u0441\u0442\u0432\u0438\u0435: \u043F\u0440\u0438\u043C\u0435\u043D\u0438\u0442\u044C \u044F\u0440\u043B\u044B\u043A \xAB\u041E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u0435\u043C\u044B\u0435 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438\xBB \u0438 \u043F\u0440\u043E\u043F\u0443\u0441\u0442\u0438\u0442\u044C \u0432\u0445\u043E\u0434\u044F\u0449\u0438\u0435",
      tip1L3: "\u0420\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442: \u043F\u0438\u0441\u044C\u043C\u0430 \u0441 plus-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u0435\u0439 \u043C\u043E\u0436\u043D\u043E \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0443\u0432\u043E\u0434\u0438\u0442\u044C \u0438\u0437 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0433\u043E \u044F\u0449\u0438\u043A\u0430, \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u044F \u0435\u0433\u043E \u0447\u0438\u0441\u0442\u044B\u043C",
      tip2Title: "2. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0441\u043E\u0433\u043B\u0430\u0448\u0435\u043D\u0438\u0439 \u043E\u0431 \u0438\u043C\u0435\u043D\u043E\u0432\u0430\u043D\u0438\u0438",
      tip2P1: "\u0420\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0430\u0439\u0442\u0435 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u0443\u044E \u0441\u0438\u0441\u0442\u0435\u043C\u0443 \u0442\u0435\u0433\u043E\u0432:",
      tip2L1: "+shop-[\u043D\u0430\u0437\u0432\u0430\u043D\u0438\u0435_\u0441\u0430\u0439\u0442\u0430] \u2014 \u0418\u043D\u0442\u0435\u0440\u043D\u0435\u0442-\u043C\u0430\u0433\u0430\u0437\u0438\u043D\u044B",
      tip2L2: "+news-[\u0442\u0435\u043C\u0430] \u2014 \u0420\u0430\u0441\u0441\u044B\u043B\u043A\u0438",
      tip2L3: "+trial-[\u0441\u0435\u0440\u0432\u0438\u0441] \u2014 \u0411\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0435 \u043F\u0440\u043E\u0431\u043D\u044B\u0435 \u0432\u0435\u0440\u0441\u0438\u0438",
      tip2L4: "+social-[\u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430] \u2014 \u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0435 \u0441\u0435\u0442\u0438",
      tip3Title: "3. \u041E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0435 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u043E\u0432 \u0443\u0442\u0435\u0447\u043A\u0438 \u0434\u0430\u043D\u043D\u044B\u0445",
      tip3P1: "\u041A\u043E\u0433\u0434\u0430 \u0432\u044B \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442\u0435 \u0441\u043F\u0430\u043C \u0438\u043B\u0438 \u0444\u0438\u0448\u0438\u043D\u0433\u043E\u0432\u044B\u0435 \u043F\u0438\u0441\u044C\u043C\u0430, \u043F\u0440\u043E\u0432\u0435\u0440\u044C\u0442\u0435 \u043F\u043E\u043B\u0435 \xAB\u041A\u043E\u043C\u0443\xBB. \u0415\u0441\u043B\u0438 \u0442\u0430\u043C \u0443\u043A\u0430\u0437\u0430\u043D yourname+specific_site@gmail.com, \u0432\u044B \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0438\u043B\u0438 \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A \u0443\u0442\u0435\u0447\u043A\u0438.",
      ctaTitle: "\u041D\u0430\u0447\u043D\u0438\u0442\u0435 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u044C \u0444\u0443\u043D\u043A\u0446\u0438\u0438 \u043A\u043E\u043D\u0444\u0438\u0434\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 Gmail \u0443\u0436\u0435 \u0441\u0435\u0433\u043E\u0434\u043D\u044F",
      ctaP1: "\u041F\u043B\u044E\u0441-\u0430\u0434\u0440\u0435\u0441\u0430\u0446\u0438\u044F \u0438 \u0442\u0440\u044E\u043A \u0441 \u0442\u043E\u0447\u043A\u043E\u0439 Gmail \u2014 \u044D\u0442\u043E \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0435 \u0432\u0441\u0442\u0440\u043E\u0435\u043D\u043D\u044B\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0438, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0442 \u043F\u0440\u044F\u043C\u043E \u0441\u0435\u0439\u0447\u0430\u0441 \u0441 \u0432\u0430\u0448\u0438\u043C \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0449\u0438\u043C \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u043E\u043C Gmail. \u0411\u0435\u0437 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438, \u0431\u0435\u0437 \u0441\u0442\u043E\u0440\u043E\u043D\u043D\u0438\u0445 \u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432, \u0431\u0435\u0437 \u0440\u0438\u0441\u043A\u0430.",
      ctaP2: "\u0414\u043B\u044F \u0441\u0438\u0442\u0443\u0430\u0446\u0438\u0439, \u0442\u0440\u0435\u0431\u0443\u044E\u0449\u0438\u0445 \u043F\u043E\u043B\u043D\u043E\u0439 \u0430\u043D\u043E\u043D\u0438\u043C\u043D\u043E\u0441\u0442\u0438: \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0435 email-\u0430\u0434\u0440\u0435\u0441\u0430 Fire Temp Mail \u043D\u0430 \u0433\u043B\u0430\u0432\u043D\u043E\u0439 \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0435."
    };
    burnerEmailPage7 = {
      h1: "\u0411\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0439 \u0433\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440 \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u043E\u0439 \u043F\u043E\u0447\u0442\u044B \u2014 \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0430\u043D\u043E\u043D\u0438\u043C\u043D\u044B\u0435 \u0430\u0434\u0440\u0435\u0441\u0430 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E",
      lead: "\u0421\u043E\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0430\u043D\u043E\u043D\u0438\u043C\u043D\u044B\u0435 email-\u0430\u0434\u0440\u0435\u0441\u0430 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E. \u0418\u0434\u0435\u0430\u043B\u044C\u043D\u043E \u0434\u043B\u044F \u0437\u0430\u0449\u0438\u0442\u044B \u0432\u0430\u0448\u0435\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0439 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438 \u0432 \u0438\u043D\u0442\u0435\u0440\u043D\u0435\u0442\u0435 \u2014 \u0431\u0435\u0437 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u0438 \u0431\u0435\u0437 \u043B\u0438\u0447\u043D\u044B\u0445 \u0434\u0430\u043D\u043D\u044B\u0445.",
      seoTitle: "\u0427\u0442\u043E \u0442\u0430\u043A\u043E\u0435 \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0439 email \u0438 \u0437\u0430\u0447\u0435\u043C \u043E\u043D \u043D\u0443\u0436\u0435\u043D?",
      seoP1: "\u041E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0439 email (burner email) \u2014 \u044D\u0442\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 \u0430\u0434\u0440\u0435\u0441 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B, \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u044E\u0449\u0438\u0439 \u043E\u0442\u043F\u0440\u0430\u0432\u043B\u044F\u0442\u044C \u0438 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u044C \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F, \u043D\u0435 \u0440\u0430\u0441\u043A\u0440\u044B\u0432\u0430\u044F \u0441\u0432\u043E\u044E \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0443\u044E \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C.",
      seoP2: "\u0422\u0435\u0440\u043C\u0438\u043D \xAB\u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0439\xBB \u0432\u0434\u043E\u0445\u043D\u043E\u0432\u043B\u0451\u043D \xAB\u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u043C\u0438 \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0430\u043C\u0438\xBB \u2014 \u043D\u0435\u043E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u0435\u043C\u044B\u043C\u0438 \u043F\u0440\u0435\u0434\u043E\u043F\u043B\u0430\u0447\u0435\u043D\u043D\u044B\u043C\u0438 \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0430\u043C\u0438, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u043C\u044B\u043C\u0438 \u0434\u043B\u044F \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u0441\u0432\u044F\u0437\u0438.",
      howTitle: "\u041A\u0430\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u0430\u044F \u043F\u043E\u0447\u0442\u0430",
      howP1: "\u0421\u0435\u0440\u0432\u0438\u0441\u044B \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u043E\u0439 \u043F\u043E\u0447\u0442\u044B, \u0442\u0430\u043A\u0438\u0435 \u043A\u0430\u043A Fire Temp Mail, \u0441\u043E\u0437\u0434\u0430\u044E\u0442 \u0441\u043B\u0443\u0447\u0430\u0439\u043D\u044B\u0439 email-\u0430\u0434\u0440\u0435\u0441 \u0432 \u043C\u043E\u043C\u0435\u043D\u0442 \u043F\u043E\u0441\u0435\u0449\u0435\u043D\u0438\u044F \u0441\u0430\u0439\u0442\u0430. \u041D\u0435 \u0442\u0440\u0435\u0431\u0443\u0435\u0442\u0441\u044F \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435 \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u0430 \u0438\u043B\u0438 \u043F\u0440\u0435\u0434\u043E\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043B\u0438\u0447\u043D\u043E\u0439 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u0438.",
      howL1: "\u041C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435: \u043F\u043E\u0441\u0435\u0442\u0438\u0442\u0435 \u0441\u0430\u0439\u0442 \u0438 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u0435 \u0441\u043B\u0443\u0447\u0430\u0439\u043D\u044B\u0439 \u0430\u043D\u043E\u043D\u0438\u043C\u043D\u044B\u0439 email-\u0430\u0434\u0440\u0435\u0441.",
      howL2: "\u041F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u0435 \u043F\u0438\u0441\u0435\u043C: \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u0430\u0434\u0440\u0435\u0441 \u0434\u043B\u044F \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u043D\u0430 \u0441\u0435\u0440\u0432\u0438\u0441\u0430\u0445 \u0438\u043B\u0438 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u043A\u043E\u0434\u043E\u0432 \u043F\u043E\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043D\u0438\u044F.",
      howL3: "\u041D\u0435\u0442 \u0441\u0432\u044F\u0437\u0438 \u0441 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u044C\u044E: \u0430\u0434\u0440\u0435\u0441 \u043D\u0435 \u0438\u043C\u0435\u0435\u0442 \u0441\u0432\u044F\u0437\u0438 \u0441 \u0432\u0430\u0448\u0438\u043C \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u043C \u0438\u043C\u0435\u043D\u0435\u043C, \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u043E\u043C \u0438\u043B\u0438 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u044B\u043C email.",
      howL4: "\u0410\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0435 \u0438\u0441\u0442\u0435\u0447\u0435\u043D\u0438\u0435: \u0447\u0435\u0440\u0435\u0437 \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u0439 \u043F\u0435\u0440\u0438\u043E\u0434 (\u043E\u0431\u044B\u0447\u043D\u043E 24 \u0447\u0430\u0441\u0430) \u0430\u0434\u0440\u0435\u0441 \u0438 \u0432\u0441\u0435 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F \u0431\u0435\u0437\u0432\u043E\u0437\u0432\u0440\u0430\u0442\u043D\u043E \u0443\u0434\u0430\u043B\u044F\u044E\u0442\u0441\u044F.",
      howL5: "\u041D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0430\u0434\u0440\u0435\u0441\u043E\u0432: \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0441\u0442\u043E\u043B\u044C\u043A\u043E \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0445 \u0430\u0434\u0440\u0435\u0441\u043E\u0432, \u0441\u043A\u043E\u043B\u044C\u043A\u043E \u043D\u0443\u0436\u043D\u043E. \u041A\u0430\u0436\u0434\u044B\u0439 \u0438\u0437 \u043D\u0438\u0445 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043D\u0435\u0437\u0430\u0432\u0438\u0441\u0438\u043C.",
      usesTitle: "\u041E\u0441\u043D\u043E\u0432\u043D\u044B\u0435 \u0441\u043B\u0443\u0447\u0430\u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u043E\u0439 \u043F\u043E\u0447\u0442\u044B",
      use1Title: "1. \u0420\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u044F \u043D\u0430 \u0441\u0430\u0439\u0442\u0430\u0445 \u0438 \u0441\u0435\u0440\u0432\u0438\u0441\u0430\u0445",
      use1P: "\u0411\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0441\u0430\u0439\u0442\u043E\u0432 \u0442\u0440\u0435\u0431\u0443\u044E\u0442 email \u0434\u043B\u044F \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u0430. \u041E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u0430\u044F \u043F\u043E\u0447\u0442\u0430 \u043F\u043E\u0437\u0432\u043E\u043B\u044F\u0435\u0442 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F, \u043D\u0435 \u043F\u043E\u0434\u0432\u0435\u0440\u0433\u0430\u044F \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0439 \u044F\u0449\u0438\u043A \u0440\u0435\u043A\u043B\u0430\u043C\u043D\u044B\u043C \u0440\u0430\u0441\u0441\u044B\u043B\u043A\u0430\u043C.",
      use2Title: "2. \u0420\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u044F \u043D\u0430 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0435 \u043F\u0440\u043E\u0431\u043D\u044B\u0435 \u0432\u0435\u0440\u0441\u0438\u0438",
      use2P: "\u041C\u043D\u043E\u0433\u0438\u0435 \u0441\u0435\u0440\u0432\u0438\u0441\u044B \u043F\u0440\u0435\u0434\u043B\u0430\u0433\u0430\u044E\u0442 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0435 \u043F\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0438 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0435 \u043F\u0440\u043E\u0431\u043D\u044B\u0435 \u0432\u0435\u0440\u0441\u0438\u0438, \u043D\u043E \u0442\u0440\u0435\u0431\u0443\u044E\u0442 email. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u0443\u044E \u043F\u043E\u0447\u0442\u0443, \u0447\u0442\u043E\u0431\u044B \u043F\u043E\u043F\u0440\u043E\u0431\u043E\u0432\u0430\u0442\u044C \u0441\u0435\u0440\u0432\u0438\u0441 \u0431\u0435\u0437 \u0440\u0438\u0441\u043A\u0430.",
      use3Title: "3. \u041E\u043D\u043B\u0430\u0439\u043D-\u043F\u043E\u043A\u0443\u043F\u043A\u0438 \u0438 \u043A\u0443\u043F\u043E\u043D\u044B",
      use3P: "\u0420\u043E\u0437\u043D\u0438\u0447\u043D\u044B\u0435 \u0441\u0430\u0439\u0442\u044B \u0447\u0430\u0441\u0442\u043E \u0442\u0440\u0435\u0431\u0443\u044E\u0442 email \u0434\u043B\u044F \u043E\u0444\u043E\u0440\u043C\u043B\u0435\u043D\u0438\u044F \u0437\u0430\u043A\u0430\u0437\u0430 \u0438\u043B\u0438 \u043F\u043E\u043B\u0443\u0447\u0435\u043D\u0438\u044F \u0441\u043A\u0438\u0434\u043E\u043A. \u041E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u0430\u044F \u043F\u043E\u0447\u0442\u0430 \u043F\u0440\u0435\u0434\u043E\u0442\u0432\u0440\u0430\u0449\u0430\u0435\u0442 \u0441\u043F\u0430\u043C \u043F\u043E\u0441\u043B\u0435 \u043F\u043E\u043A\u0443\u043F\u043A\u0438.",
      use4Title: "4. \u041F\u043E\u0434\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435 \u043A \u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C\u0443 Wi-Fi",
      use4P: "\u041A\u0430\u0444\u0435, \u0430\u044D\u0440\u043E\u043F\u043E\u0440\u0442\u044B \u0438 \u043E\u0442\u0435\u043B\u0438 \u0447\u0430\u0441\u0442\u043E \u0442\u0440\u0435\u0431\u0443\u044E\u0442 email \u0434\u043B\u044F \u0434\u043E\u0441\u0442\u0443\u043F\u0430 \u043A \u0441\u0432\u043E\u0438\u043C \u0441\u0435\u0442\u044F\u043C Wi-Fi.",
      use5Title: "5. \u0421\u043A\u0430\u0447\u0438\u0432\u0430\u043D\u0438\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u043E\u0432",
      use5P: "\u042D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0435 \u043A\u043D\u0438\u0433\u0438, \u0431\u0435\u043B\u044B\u0435 \u043A\u043D\u0438\u0433\u0438, \u0448\u0430\u0431\u043B\u043E\u043D\u044B \u0438 \u0434\u0440\u0443\u0433\u0438\u0435 \u0437\u0430\u0433\u0440\u0443\u0436\u0430\u0435\u043C\u044B\u0435 \u0440\u0435\u0441\u0443\u0440\u0441\u044B \u043E\u0431\u044B\u0447\u043D\u043E \u0442\u0440\u0435\u0431\u0443\u044E\u0442 \u0443\u043A\u0430\u0437\u0430\u043D\u0438\u044F email.",
      use6Title: "6. \u0420\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u044F \u043D\u0430 \u0444\u043E\u0440\u0443\u043C\u0430\u0445 \u0438 \u0432 \u0441\u043E\u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430\u0445",
      use6P: "\u0424\u043E\u0440\u0443\u043C\u044B \u0438 \u0434\u0438\u0441\u043A\u0443\u0441\u0441\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u043E\u043E\u0431\u0449\u0435\u0441\u0442\u0432\u0430 \u0447\u0430\u0441\u0442\u043E \u0442\u0440\u0435\u0431\u0443\u044E\u0442 email \u0434\u043B\u044F \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u044F \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u043E\u0432. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u0443\u044E \u043F\u043E\u0447\u0442\u0443 \u0434\u043B\u044F \u0430\u043D\u043E\u043D\u0438\u043C\u043D\u043E\u0433\u043E \u0443\u0447\u0430\u0441\u0442\u0438\u044F.",
      use7Title: "7. \u0420\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u043A\u0430 \u0438 QA-\u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435",
      use7P: "\u0420\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u0430\u043C \u0438 \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0449\u0438\u043A\u0430\u043C \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043D\u0443\u0436\u043D\u044B \u0441\u0432\u0435\u0436\u0438\u0435 email-\u0430\u0434\u0440\u0435\u0441\u0430 \u0434\u043B\u044F \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u0432 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u0438 \u0441\u0438\u0441\u0442\u0435\u043C \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438.",
      benefitsTitle: "\u041F\u0440\u0435\u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0438\u044F \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u043E\u0439 \u043F\u043E\u0447\u0442\u044B",
      ben1: "\u0417\u0430\u0449\u0438\u0442\u0430 \u043A\u043E\u043D\u0444\u0438\u0434\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438: \u0432\u0430\u0448 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u0439 email \u043E\u0441\u0442\u0430\u0451\u0442\u0441\u044F \u0441\u043A\u0440\u044B\u0442\u044B\u043C. \u041D\u0438\u043A\u0442\u043E \u043D\u0435 \u0441\u043C\u043E\u0436\u0435\u0442 \u043E\u0442\u0441\u043B\u0435\u0434\u0438\u0442\u044C \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0439 email \u0434\u043E \u0432\u0430\u0441.",
      ben2: "\u041F\u0440\u0435\u0434\u043E\u0442\u0432\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u0441\u043F\u0430\u043C\u0430: \u0432\u0435\u0441\u044C \u0441\u043F\u0430\u043C \u0438\u0434\u0451\u0442 \u043D\u0430 \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0439 \u0430\u0434\u0440\u0435\u0441, \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u044F \u0432\u0430\u0448 \u0440\u0435\u0430\u043B\u044C\u043D\u044B\u0439 \u044F\u0449\u0438\u043A \u0447\u0438\u0441\u0442\u044B\u043C.",
      ben3: "\u0411\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u0438 \u0443\u0442\u0435\u0447\u043A\u0430\u0445: \u0435\u0441\u043B\u0438 \u0441\u0435\u0440\u0432\u0438\u0441, \u043D\u0430 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0432\u044B \u0437\u0430\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u043B\u0438\u0441\u044C, \u0431\u0443\u0434\u0435\u0442 \u0432\u0437\u043B\u043E\u043C\u0430\u043D, \u0432\u0430\u0448\u0435\u0433\u043E \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E email \u043D\u0435 \u0431\u0443\u0434\u0435\u0442 \u0432 \u0443\u0442\u0435\u0447\u043A\u0435.",
      ben4: "\u0411\u0435\u0437 \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u0430\u043C\u0438: \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u043F\u0430\u0440\u043E\u043B\u0435\u0439 \u0434\u043B\u044F \u0437\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F. \u041D\u0438\u043A\u0430\u043A\u0438\u0445 \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0445 \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u043E\u0432 \u0434\u043B\u044F \u043E\u0431\u0441\u043B\u0443\u0436\u0438\u0432\u0430\u043D\u0438\u044F.",
      ben5: "\u041C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E \u0438 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E: \u0431\u0435\u0437 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438. \u0411\u0435\u0437 \u0437\u0430\u0442\u0440\u0430\u0442. \u041F\u0440\u043E\u0441\u0442\u043E \u0437\u0430\u0439\u0434\u0438\u0442\u0435, \u0441\u043E\u0437\u0434\u0430\u0439\u0442\u0435 \u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435.",
      vsTitle: "\u041E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u0430\u044F \u043F\u043E\u0447\u0442\u0430 vs. \u043E\u0431\u044B\u0447\u043D\u0430\u044F \u043F\u043E\u0447\u0442\u0430 vs. \u043F\u0441\u0435\u0432\u0434\u043E\u043D\u0438\u043C\u044B email",
      vsP1: "\u041E\u0431\u044B\u0447\u043D\u0430\u044F \u043F\u043E\u0447\u0442\u0430 (Gmail, Outlook): \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u0430\u044F, \u043F\u0440\u0438\u0432\u044F\u0437\u0430\u043D\u0430 \u043A \u0432\u0430\u0448\u0435\u0439 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438, \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0435\u0442\u0441\u044F \u0434\u043B\u044F \u0434\u043E\u043B\u0433\u043E\u0441\u0440\u043E\u0447\u043D\u043E\u0439 \u043F\u0435\u0440\u0435\u043F\u0438\u0441\u043A\u0438.",
      vsP2: "\u041F\u0441\u0435\u0432\u0434\u043E\u043D\u0438\u043C\u044B email (+\u0442\u0435\u0433\u0438, \u0442\u043E\u0447\u043A\u0438): \u0432\u0430\u0440\u0438\u0430\u0446\u0438\u0438 \u0432\u0430\u0448\u0435\u0433\u043E \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0433\u043E email, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0434\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0432 \u0432\u0430\u0448 \u044F\u0449\u0438\u043A. \u041F\u043E\u043B\u0435\u0437\u043D\u044B \u0434\u043B\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438, \u043D\u043E \u043D\u0435 \u0441\u043A\u0440\u044B\u0432\u0430\u044E\u0442 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u0430\u0434\u0440\u0435\u0441.",
      vsP3: "\u041E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u0430\u044F \u043F\u043E\u0447\u0442\u0430 (Fire Temp Mail): \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0442\u0434\u0435\u043B\u0435\u043D\u0430 \u043E\u0442 \u0432\u0430\u0448\u0435\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0439 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438. \u0412\u0440\u0435\u043C\u0435\u043D\u043D\u0430\u044F, \u0430\u043D\u043E\u043D\u0438\u043C\u043D\u0430\u044F, \u0441\u0430\u043C\u043E\u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u044E\u0449\u0430\u044F\u0441\u044F."
    };
    eduEmailPage7 = {
      h1: "\u0411\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0439 \u0433\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440 EDU email \u2014 \u0441\u043E\u0437\u0434\u0430\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 \u043F\u043E\u0447\u0442\u043E\u0432\u044B\u0439 \u044F\u0449\u0438\u043A .EDU \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E",
      lead: "\u0413\u0435\u043D\u0435\u0440\u0438\u0440\u0443\u0439\u0442\u0435 .EDU email \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043D\u0430\u0448\u0435\u0433\u043E \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E\u0433\u043E \u0433\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440\u0430 EDU email. \u0418\u0434\u0435\u0430\u043B\u044C\u043D\u043E \u0434\u043B\u044F \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0439, \u0442\u0435\u0441\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u0441\u0442\u0443\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0438\u0445 \u0441\u043A\u0438\u0434\u043E\u043A.",
      seoTitle: "\u041B\u0443\u0447\u0448\u0438\u0435 \u0441\u0442\u0443\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0438\u0435 \u0441\u043A\u0438\u0434\u043A\u0438 \u0438 \u043F\u0440\u0435\u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u0430 .EDU email",
      seoP1: "\u0421\u0442\u0443\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0438\u0435 \u0441\u043A\u0438\u0434\u043A\u0438 \u043C\u043E\u0433\u0443\u0442 \u0441\u044D\u043A\u043E\u043D\u043E\u043C\u0438\u0442\u044C \u0432\u0430\u043C \u0442\u044B\u0441\u044F\u0447\u0438 \u0432 \u0433\u043E\u0434 \u043D\u0430 \u043F\u0440\u043E\u0433\u0440\u0430\u043C\u043C\u043D\u043E\u043C \u043E\u0431\u0435\u0441\u043F\u0435\u0447\u0435\u043D\u0438\u0438, \u0441\u0442\u0440\u0438\u043C\u0438\u043D\u0433\u043E\u0432\u044B\u0445 \u0441\u0435\u0440\u0432\u0438\u0441\u0430\u0445 \u0438 \u0443\u0447\u0435\u0431\u043D\u044B\u0445 \u0440\u0435\u0441\u0443\u0440\u0441\u0430\u0445.",
      discountsTitle: "\u041B\u0443\u0447\u0448\u0438\u0435 \u0441\u0442\u0443\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0438\u0435 \u0441\u043A\u0438\u0434\u043A\u0438 \u0441 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0435\u0439 .EDU",
      spotifyTitle: "Spotify Premium \u0434\u043B\u044F \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432 \u2014 $5.99/\u043C\u0435\u0441 (\u0441\u043A\u0438\u0434\u043A\u0430 50%)",
      spotifyP1: "\u041E\u0431\u044B\u0447\u043D\u0430\u044F \u0446\u0435\u043D\u0430: $10.99/\u043C\u0435\u0441 | \u042D\u043A\u043E\u043D\u043E\u043C\u0438\u044F \u0434\u043B\u044F \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432: $60/\u0433\u043E\u0434",
      spotifyP2: "\u0412\u043A\u043B\u044E\u0447\u0430\u0435\u0442 Hulu (\u0441 \u0440\u0435\u043A\u043B\u0430\u043C\u043E\u0439) \u0438 SHOWTIME \u0431\u0435\u0437 \u0434\u043E\u043F\u043E\u043B\u043D\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u043F\u043B\u0430\u0442\u044B.",
      amazonTitle: "Amazon Prime \u0434\u043B\u044F \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432 \u2014 $7.49/\u043C\u0435\u0441",
      amazonP1: "\u041E\u0431\u044B\u0447\u043D\u0430\u044F \u0446\u0435\u043D\u0430: $14.99/\u043C\u0435\u0441 | \u042D\u043A\u043E\u043D\u043E\u043C\u0438\u044F \u0434\u043B\u044F \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432: $90/\u0433\u043E\u0434 + 6 \u043C\u0435\u0441\u044F\u0446\u0435\u0432 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E\u0433\u043E \u043F\u0440\u043E\u0431\u043D\u043E\u0433\u043E \u043F\u0435\u0440\u0438\u043E\u0434\u0430",
      amazonP2: "\u0412\u0441\u0435 \u043F\u0440\u0435\u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u0430 Prime: \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u0430\u044F \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0430 \u0437\u0430 2 \u0434\u043D\u044F, Prime Video, Prime Music, \u0431\u0435\u0437\u043B\u0438\u043C\u0438\u0442\u043D\u043E\u0435 \u0445\u0440\u0430\u043D\u0438\u043B\u0438\u0449\u0435 \u0444\u043E\u0442\u043E\u0433\u0440\u0430\u0444\u0438\u0439 \u0438 \u043C\u043D\u043E\u0433\u043E\u0435 \u0434\u0440\u0443\u0433\u043E\u0435.",
      adobeTitle: "Adobe Creative Cloud \u2014 \u0441\u043A\u0438\u0434\u043A\u0430 60%",
      adobeP1: "\u041E\u0431\u044B\u0447\u043D\u0430\u044F \u0446\u0435\u043D\u0430: $59.99/\u043C\u0435\u0441 | \u0421\u0442\u0443\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0430\u044F \u0446\u0435\u043D\u0430: $19.99/\u043C\u0435\u0441 | \u042D\u043A\u043E\u043D\u043E\u043C\u0438\u044F: $480/\u0433\u043E\u0434",
      adobeP2: "\u041F\u043E\u043B\u043D\u044B\u0439 \u043D\u0430\u0431\u043E\u0440: Photoshop, Illustrator, Premiere Pro, After Effects, InDesign \u0438 \u0431\u043E\u043B\u0435\u0435 20 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0439.",
      appleTitle: "Apple Music \u0434\u043B\u044F \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432 \u2014 $5.99/\u043C\u0435\u0441",
      appleP1: "\u041E\u0431\u044B\u0447\u043D\u0430\u044F \u0446\u0435\u043D\u0430: $10.99/\u043C\u0435\u0441 | \u042D\u043A\u043E\u043D\u043E\u043C\u0438\u044F \u0434\u043B\u044F \u0441\u0442\u0443\u0434\u0435\u043D\u0442\u043E\u0432: $60/\u0433\u043E\u0434",
      appleP2: "\u041F\u043E\u043B\u043D\u044B\u0439 \u043A\u0430\u0442\u0430\u043B\u043E\u0433 Apple Music \u043F\u043B\u044E\u0441 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u0430\u044F \u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0430 Apple TV+.",
      githubTitle: "GitHub Student Developer Pack \u2014 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E",
      githubP1: "\u041E\u0431\u044B\u0447\u043D\u0430\u044F \u0441\u0442\u043E\u0438\u043C\u043E\u0441\u0442\u044C: $200+/\u0433\u043E\u0434 \u0432 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430\u0445 | \u0421\u0442\u0443\u0434\u0435\u043D\u0447\u0435\u0441\u043A\u0430\u044F \u0446\u0435\u043D\u0430: \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E",
      githubP2: "GitHub Pro, \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E\u0435 \u0434\u043E\u043C\u0435\u043D\u043D\u043E\u0435 \u0438\u043C\u044F, \u043E\u0431\u043B\u0430\u0447\u043D\u044B\u0435 \u043A\u0440\u0435\u0434\u0438\u0442\u044B, \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B CI/CD \u0438 \u0431\u043E\u043B\u0435\u0435 20 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438 \u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432 \u0434\u043B\u044F \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432."
    };
    bestTempMailPage7 = {
      h1: "Best Temp Mail \u2014 \u043B\u0443\u0447\u0448\u0438\u0439 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0439 \u0441\u0435\u0440\u0432\u0438\u0441 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B",
      lead: "\u041B\u0443\u0447\u0448\u0438\u0439 \u0441\u0435\u0440\u0432\u0438\u0441 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B \u0432 \u0438\u043D\u0442\u0435\u0440\u043D\u0435\u0442\u0435. \u0421\u043E\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u044B\u0435 \u043E\u0434\u043D\u043E\u0440\u0430\u0437\u043E\u0432\u044B\u0435 email-\u0430\u0434\u0440\u0435\u0441\u0430 \u2014 \u0431\u0435\u0437 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u0438 \u0431\u0435\u0437 \u043B\u0438\u0447\u043D\u044B\u0445 \u0434\u0430\u043D\u043D\u044B\u0445. \u041F\u0440\u0438\u0432\u0430\u0442\u043D\u043E, \u0431\u044B\u0441\u0442\u0440\u043E \u0438 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u043E.",
      seoTitle: "\u041F\u043E\u0447\u0435\u043C\u0443 Fire Temp Mail \u2014 \u043B\u0443\u0447\u0448\u0438\u0439 \u0441\u0435\u0440\u0432\u0438\u0441 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B",
      seoP1: "\u041F\u0440\u0438 \u043D\u0430\u043B\u0438\u0447\u0438\u0438 \u0434\u0435\u0441\u044F\u0442\u043A\u043E\u0432 \u0441\u0435\u0440\u0432\u0438\u0441\u043E\u0432 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B \u0432 \u0438\u043D\u0442\u0435\u0440\u043D\u0435\u0442\u0435 \u0432\u044B\u0431\u043E\u0440 \u043F\u0440\u0430\u0432\u0438\u043B\u044C\u043D\u043E\u0433\u043E \u0438\u043C\u0435\u0435\u0442 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435. Fire Temp Mail \u0432\u044B\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043B\u0443\u0447\u0448\u0438\u0439.",
      comparison: "\u0421\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u0435 \u0444\u0443\u043D\u043A\u0446\u0438\u0439 \u0441 \u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u0435\u0440\u0432\u0438\u0441\u0430\u043C\u0438",
      whyBestTitle: "\u0427\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u0442 \u043D\u0430\u0441 \u043B\u0443\u0447\u0448\u0438\u043C\u0438",
      whyBestP1: "Fire Temp Mail \u0441\u043E\u0447\u0435\u0442\u0430\u0435\u0442 \u0441\u043A\u043E\u0440\u043E\u0441\u0442\u044C, \u043A\u043E\u043D\u0444\u0438\u0434\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438 \u043F\u0440\u043E\u0441\u0442\u043E\u0442\u0443 \u0442\u0430\u043A, \u043A\u0430\u043A \u043D\u0438 \u043E\u0434\u0438\u043D \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0435\u0440\u0432\u0438\u0441 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0439 \u043F\u043E\u0447\u0442\u044B.",
      feature1: "\u041C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E\u0435 \u0441\u043E\u0437\u0434\u0430\u043D\u0438\u0435: \u0431\u0435\u0437 \u043E\u0436\u0438\u0434\u0430\u043D\u0438\u044F, \u0431\u0435\u0437 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438. \u041E\u0442\u043A\u0440\u043E\u0439\u0442\u0435 \u0441\u0442\u0440\u0430\u043D\u0438\u0446\u0443 \u2014 \u0438 \u0432\u0430\u0448 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 email \u0433\u043E\u0442\u043E\u0432 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E.",
      feature2: "\u041C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u0434\u043E\u043C\u0435\u043D\u043E\u0432: \u0432\u044B\u0431\u0438\u0440\u0430\u0439\u0442\u0435 \u0438\u0437 \u043D\u0435\u0441\u043A\u043E\u043B\u044C\u043A\u0438\u0445 \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0445 email-\u0434\u043E\u043C\u0435\u043D\u043E\u0432.",
      feature3: "\u0410\u0434\u0440\u0435\u0441\u0430 \u0432 \u0441\u0442\u0438\u043B\u0435 Gmail: \u043F\u043E\u043B\u0443\u0447\u0430\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 \u0430\u0434\u0440\u0435\u0441\u0430, \u043F\u043E\u0445\u043E\u0436\u0438\u0435 \u043D\u0430 Gmail, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0442 \u0432\u0435\u0437\u0434\u0435.",
      feature4: "\u041F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u0441\u043A\u0438\u0435 \u043F\u0441\u0435\u0432\u0434\u043E\u043D\u0438\u043C\u044B: \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 \u0430\u0434\u0440\u0435\u0441\u0430 \u0434\u043B\u044F \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0438.",
      feature5: "\u0410\u0432\u0442\u043E\u043E\u0431\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \u0432\u0445\u043E\u0434\u044F\u0449\u0438\u0445: \u043D\u043E\u0432\u044B\u0435 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F \u043F\u043E\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438.",
      feature6: "\u041A\u043E\u043D\u0444\u0438\u0434\u0435\u043D\u0446\u0438\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u0435\u0436\u0434\u0435 \u0432\u0441\u0435\u0433\u043E: \u0431\u0435\u0437 \u043E\u0442\u0441\u043B\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u044F, \u0431\u0435\u0437 \u043B\u043E\u0433\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0431\u0435\u0437 \u0441\u0431\u043E\u0440\u0430 \u0434\u0430\u043D\u043D\u044B\u0445."
    };
    gmailGeneratorPage7 = {
      h1: "\u0411\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0439 \u0433\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440 Gmail \u2014 \u0441\u043E\u0437\u0434\u0430\u0432\u0430\u0439\u0442\u0435 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 \u0430\u0434\u0440\u0435\u0441\u0430 Gmail \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E",
      lead: "\u0421\u0433\u0435\u043D\u0435\u0440\u0438\u0440\u0443\u0439\u0442\u0435 \u0431\u0435\u0441\u043F\u043B\u0430\u0442\u043D\u044B\u0439 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 \u0430\u0434\u0440\u0435\u0441 Gmail \u0441 \u043F\u043E\u043C\u043E\u0449\u044C\u044E \u043D\u0430\u0448\u0435\u0433\u043E \u0433\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440\u0430 Gmail. \u041C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u044B\u0439 \u0434\u043E\u0441\u0442\u0443\u043F \u043A \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u043C\u0443 \u043F\u043E\u0447\u0442\u043E\u0432\u043E\u043C\u0443 \u044F\u0449\u0438\u043A\u0443 Gmail \u2014 \u0431\u0435\u0437 \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u0438 \u0431\u0435\u0437 \u043B\u0438\u0447\u043D\u044B\u0445 \u0434\u0430\u043D\u043D\u044B\u0445.",
      seoTitle: "\u041A\u0430\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0433\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440 Gmail",
      seoP1: "\u041D\u0430\u0448 \u0433\u0435\u043D\u0435\u0440\u0430\u0442\u043E\u0440 Gmail \u0441\u043E\u0437\u0434\u0430\u0451\u0442 \u0432\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0435 \u0430\u0434\u0440\u0435\u0441\u0430 \u0432 \u0441\u0442\u0438\u043B\u0435 Gmail, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0440\u0430\u0431\u043E\u0442\u0430\u044E\u0442 \u0442\u0430\u043A \u0436\u0435, \u043A\u0430\u043A \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u0435 \u0430\u043A\u043A\u0430\u0443\u043D\u0442\u044B Gmail.",
      howItWorksTitle: "\u041A\u0430\u043A \u044D\u0442\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442",
      howItWorksP1: "1. \u041F\u043E\u0441\u0435\u0442\u0438\u0442\u0435 Fire Temp Mail \u0438 \u0432\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u043E\u043F\u0446\u0438\u044E Gmail. 2. \u0412\u0440\u0435\u043C\u0435\u043D\u043D\u044B\u0439 \u0430\u0434\u0440\u0435\u0441 \u0432 \u0441\u0442\u0438\u043B\u0435 Gmail \u0441\u043E\u0437\u0434\u0430\u0451\u0442\u0441\u044F \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E. 3. \u0418\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u0435\u0433\u043E \u0434\u043B\u044F \u043B\u044E\u0431\u043E\u0439 \u043E\u043D\u043B\u0430\u0439\u043D-\u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0430\u0446\u0438\u0438 \u0438\u043B\u0438 \u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u0438. 4. \u041F\u043E\u043B\u0443\u0447\u0430\u0439\u0442\u0435 \u043F\u0438\u0441\u044C\u043C\u0430 \u0432 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u043C \u0432\u0440\u0435\u043C\u0435\u043D\u0438. 5. \u0410\u0434\u0440\u0435\u0441 \u0430\u0432\u0442\u043E\u043C\u0430\u0442\u0438\u0447\u0435\u0441\u043A\u0438 \u0438\u0441\u0442\u0435\u043A\u0430\u0435\u0442 \u0447\u0435\u0440\u0435\u0437 24 \u0447\u0430\u0441\u0430."
    };
