          solution: "\u4F7F\u7528\u4E34\u65F6\u90AE\u7BB1\u83B7\u53D6\u4E0B\u8F7D\u94FE\u63A5\uFF0C\u65E0\u9700\u52A0\u5165\u4ED6\u4EEC\u7684\u90AE\u4EF6\u5217\u8868\u3002\u83B7\u53D6\u8D44\u6E90\u540E\u7EE7\u7EED\u524D\u8FDB\uFF0C\u65E0\u9700\u62C5\u5FC3\u672A\u6765\u7684\u8425\u9500\u90AE\u4EF6\u3002"
