          solution: "\u751F\u6210\u65E0\u9650\u4E34\u65F6\u90AE\u7BB1\uFF0C\u7528\u4E8E\u6D4B\u8BD5\u7528\u6237\u6CE8\u518C\u3001\u90AE\u7BB1\u9A8C\u8BC1\u3001\u901A\u77E5\u7CFB\u7EDF\u548C\u5BC6\u7801\u6062\u590D\u2014\u2014\u65E0\u9700\u7BA1\u7406\u771F\u5B9E\u8D26\u6237\u3002"
