      whyP2: "Fire Temp Mail \u63D0\u4F9B\u4E13\u4E3A\u8F6F\u4EF6\u6D4B\u8BD5\u8BBE\u8BA1\u7684\u5373\u65F6\u4E00\u6B21\u6027\u7535\u5B50\u90AE\u4EF6\u5730\u5740\u3002\u751F\u6210\u65E0\u9650\u91CF\u7684\u4E34\u65F6\u90AE\u7BB1\u6765\u6D4B\u8BD5\u60A8\u5E94\u7528\u7A0B\u5E8F\u7684\u90AE\u4EF6\u6D41\u7A0B\u3002",
      painPointsTitle: "\u5F00\u53D1\u8005\u5E38\u89C1\u75DB\u70B9\uFF08\u5DF2\u89E3\u51B3\uFF09",
