      pp2: "\u7BA1\u7406\u591A\u4E2A\u6D4B\u8BD5\u8D26\u6237\u7684\u5BC6\u7801 \u2192 \u65E0\u9700\u4EFB\u4F55\u51ED\u8BC1",
      pp3: "\u6E05\u7406\u8FC7\u671F\u7684\u6D4B\u8BD5\u6570\u636E \u2192 24\u5C0F\u65F6\u540E\u81EA\u52A8\u5220\u9664",
      pp4: "\u90AE\u4EF6\u63D0\u4F9B\u5546\u963B\u6B62\u81EA\u52A8\u6CE8\u518C \u2192 \u771F\u5B9E\u57DF\u540D\uFF0C\u9002\u7528\u4E8E\u6240\u6709\u573A\u666F",
      pp5: "\u6D4B\u8BD5\u591A\u7528\u6237\u573A\u666F \u2192 \u6309\u9700\u83B7\u53D6\u65E0\u9650\u552F\u4E00\u5730\u5740",
      pp6: "CI/CD \u6D41\u6C34\u7EBF\u9700\u8981\u65B0\u90AE\u7BB1 \u2192 \u96F6\u914D\u7F6E\u90AE\u7BB1\u751F\u6210",
      uc1Title: "1. \u7528\u6237\u6CE8\u518C\u548C\u90AE\u7BB1\u9A8C\u8BC1\u6D4B\u8BD5",
