      uc4Title: "4. \u90AE\u4EF6\u901A\u77E5\u7CFB\u7EDF\u6D4B\u8BD5",
      uc4P1: "\u5982\u679C\u60A8\u7684\u5E94\u7528\u53D1\u9001\u4E8B\u52A1\u6027\u90AE\u4EF6\uFF08\u8BA2\u5355\u786E\u8BA4\u3001\u63D0\u9192\u3001\u901A\u77E5\uFF09\uFF0C\u8BF7\u4F7F\u7528\u4E34\u65F6\u90AE\u7BB1\u6765\u9A8C\u8BC1\u90AE\u4EF6\u662F\u5426\u5728\u6B63\u786E\u7684\u4E8B\u4EF6\u4E2D\u89E6\u53D1\u3002",
      uc5Title: "5. \u81EA\u52A8\u5316\u6D4B\u8BD5\u548C CI/CD \u96C6\u6210",
